// AddExtraLibsDir add an additional directory to search for dynamic libraries.
//
// When [`get_language`](Self::get_language) cannot find a grammar in the
// primary library directory, it searches these extra directories in order.
// Typically used by the download system to register its cache directory.
//
// Takes `&self` (not `&mut self`) because `extra_lib_dirs` uses interior
// mutability via an `Arc<RwLock<...>>`, so the outer registry can remain
// immutable while the directory list is updated.
func (h *LanguageRegistry) AddExtraLibsDir(dir string) {
	cDir := C.CString(dir)
	defer C.free(unsafe.Pointer(cDir))

	C.ts_pack_language_registry_add_extra_libs_dir((*C.TS_PACKLanguageRegistry)(unsafe.Pointer(h.ptr)), cDir)
}

// GetLanguage get a tree-sitter [`Language`] by name.
//
// Resolves aliases (e.g., `"shell"` -> `"bash"`, `"makefile"` -> `"make"`),
// then looks up the language in the static table. When the `dynamic-loading`
// feature is enabled, falls back to loading a shared library on demand.
//
// # Errors
//
// Returns [`Error::LanguageNotFound`] if the name (after alias resolution)
// does not match any known grammar.
func (h *LanguageRegistry) GetLanguage(name string) (*Language, error) {
	cName := C.CString(name)
	defer C.free(unsafe.Pointer(cName))

	ptr := C.ts_pack_language_registry_get_language((*C.TS_PACKLanguageRegistry)(unsafe.Pointer(h.ptr)), cName)
	if err := lastError(); err != nil {
		return nil, err
	}
	return &Language{ptr: unsafe.Pointer(ptr)}, nil
}

